const express = require('express');
const app = express();

// route לعرض דף מחיקת טיסה
app.get('/controlpanel/delete', (req, res) => {
  // דוגמה לנתוני בדיקה קבועים
  const flights = [
    { id: 101, destination: 'תל אביב', time: '10:00' },
    { id: 102, destination: 'ניו יורק', time: '14:30' }
  ];

  // יצירת HTML דינמי (אבל דטרמיניסטי – תמיד אותו מבנה)
  const html = `
    <!DOCTYPE html>
    <html>
    <head>
      <title>מחיקת טיסה</title>
    </head>
    <body>
      <h2>מחיקת טיסה</h2>
      <form method="POST" action="/controlpanel/delete">
        <label for="flightId">מספר טיסה:</label>
        <input type="number" id="flightId" name="flightId" required>
        <button type="submit">מחק טיסה</button>
      </form>
      <h3>טיסות קיימות (לבדיקה)</h3>
      <ul>
        ${flights.map(f => `<li>טיסה ${f.id}: ${f.destination} ב-${f.time}</li>`).join('')}
      </ul>
    </body>
    </html>
  `;

  res.send(html);
});

// route לобра בקשת מחיקה (למשל, POST)
app.post('/controlpanel/delete', (req, res) => {
  const { flightId } = req.body;
  // בדיקת תקינות – flightId חייב להיות מספר
  const id = Number(flightId);
  if (isNaN(id)) {
    return res.status(400).send('שגיאה: מספר טיסה לא תקין');
  }

  // לוגיקה למחיקה – כאן פשוט מחזירים הודעה (במקרה אמת, נמחק ממערך או מסד)
  // מכיוון שמדובר בנתוני בדיקה, נניח שהמחיקה מצליחה
  res.send(`טיסה ${id} נמחקה בהצלחה!`);
});

module.exports = app;
```

