1. **משמעות המשימה**  
המשימה מבקשת לתכנן מבנה טופס (ב-React) שמאפשר למשתמש להזין ערכים שיקלטו את שם השדה, סוגו, ויתרונות נוספים (כגון חובה/לא חובה), כדי לבנות טופס דינמי.  
ההקשר הוא מטיסה למחיקה ב-`/controlpanel/delete`, אך המשימה עצמה היא **עיצוב מבנה טופס** – לא реализציה של מחיקת טיסה.  
הדרישה היא לספק **מבנה טופס מוגדר מראש** (למשל: שדה שם, שדה אימייל, שדה תאריך) עם שדות מתאימים (input types), ולוודא שהקוד הוא דטרמיניסטי ומשתמש בנתוני בדיקה קבועים.

2. **איך פותרים אותה**  
- ניצור React component שמציג טופס עם שדות מוגדרים מראש (למשל: `name`, `email`, `date`, `is_required`).
- נשתמש ב-`useState` כדי לאחסן את נתוני השדות.
- נשתמש ב-`value` ו-`onChange` לשינויים.
- נרנדר את השדות כרשימה עם `map` ו-`key`.
- נשתמש בנתוני בדיקה קבועים (array של אוביקטים) – לא בנתונים חיצוניים.
- נוכל להוסיף validation פשוט (למשל: חובה למלא שדה חובה).

3. **קוד**

```jsx
import React, { useState } from 'react';

const ClientFormInputs = () => {
  // נתוני בדיקה קבועים – מבנה טופס לדוגמה
  const initialFields = [
    { id: 'name', label: 'שם הלקוח', type: 'text', required: true },
    { id: 'email', label: 'אימייל', type: 'email', required: true },
    { id: 'flightDate', label: 'תאריך טיסה', type: 'date', required: false },
    { id: 'priority', label: 'עדיפות', type: 'select', required: false, options: ['נורמלי', 'מיידי', 'חירום'] },
  ];

  const [fields, setFields] = useState(
    initialFields.map(f => ({ ...f, value: '' }))
  );

  const handleChange = (id, value) => {
    setFields(prev =>
      prev.map(field =>
        field.id === id ? { ...field, value } : field
      )
    );
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // בדיקת חובה – פשוטה
    const missingRequired = fields.filter(f => f.required && !f.value.trim());
    if (missingRequired.length > 0) {
      alert(`שדות חובה חסרים: ${missingRequired.map(f => f.label).join(', ')}`);
      return;
    }
    console.log('Form data:', fields);
  };

  return (
    <form onSubmit={handleSubmit}>
      <h2>טופס קלט למחיקת טיסה</h2>
      {fields.map(field => (
        <div key={field.id} style={{ marginBottom: '10px' }}>
          <label>
            {field.label}
            {field.required && <span style={{ color: 'red' }}> * </span>}
            <br />
            {field.type === 'select' ? (
              <select
                value={field.value}
                onChange={e => handleChange(field.id, e.target.value)}
                required={field.required}
              >
                <option value="">בחר...</option>
                {field.options.map(opt => (
                  <option key={opt} value={opt}>{opt}</option>
                ))}
              </select>
            ) : (
              <input
                type={field.type}
                value={field.value}
                onChange={e => handleChange(field.id, e.target.value)}
                required={field.required}
              />
            )}
          </label>
        </div>
      ))}
      <button type="submit">שליחה</button>
    </form>
  );
};

