1. **משמעות המשימה**  
המשימה מבקשת לתכנן מבנה טופס (polymorphic form) שמאפשר למשתמש להזין ערכים לפי שדה וסוג שדה (למשל: טקסט, מספר, בוליאני וכו'). זה לא טופס סטטי – אלא מבנה גמיש שמתאים לדרישות שונות, כמו למשל:  
- שדה "שם" – טקסט  
- שדה "מספר מושבים" – מספר  
- שדה "האם טיסה מואצת?" – בוליאני (תיבה מסומנת)  

המטרה: לתכנן את המבנה של השדות (field definitions) ולבצע את ההטמעה ב-React, כולל עיבוד ערכים, אימות, ותגובה לשינויים.

2. **איך פותרים אותה**  
- נגדיר מערך של אובייקטים שמתאר כל שדה: שם, סוג, דרישות אימות (למשל: חובה, טווח ערכים).  
- נשתמש ב-`useState` כדי לאחסן את הערכים שהמשתמש הכניס.  
- נשתמש ב-`onChange` על כל שדה כדי לעדכן את ה-state.  
- נרנדר טופס דינמי לפי המערך.  
- נוכל להוסיף אימות בסיסי (למשל: שדה חובה, ערך מספרי בטווח).  
- נשתמש ב-`key` ייחודי ל-each input, ו-`map` ליצירת הרשימה.

3. **קוד**

```jsx
import React, { useState } from 'react';

// הגדרת שדות דינמיים
const formFields = [
  {
    id: 'flightNumber',
    label: 'מספר טיסה',
    type: 'text',
    required: true,
    placeholder: 'למשל: LY123'
  },
  {
    id: 'passengers',
    label: 'מספר נוסעים',
    type: 'number',
    required: true,
    min: 1,
    max: 500
  },
  {
    id: 'isExpress',
    label: 'טיסה מואצת',
    type: 'checkbox'
  }
];

function DynamicForm() {
  const [formData, setFormData] = useState({});
  const [errors, setErrors] = useState({});

  const handleChange = (id, value, type) => {
    // המרת ערך ל-boolean אם זה checkbox
    const finalValue = type === 'checkbox' ? value : value;

    setFormData(prev => ({
      ...prev,
      [id]: finalValue
    }));

    // ניקוי שגיאה אם השדה נערך
    if (errors[id]) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors[id];
        return newErrors;
      });
    }
  };

  const validate = () => {
    const newErrors = {};
    formFields.forEach(field => {
      const value = formData[field.id];
      if (field.required && (value === undefined || value === '')) {
        newErrors[field.id] = 'שדה חובה';
      }
      if (field.type === 'number' && value !== undefined) {
        const num = Number(value);
        if (isNaN(num) || (field.min !== undefined && num < field.min) || (field.max !== undefined && num > field.max)) {
          newErrors[field.id] = `ערך חייב להיות בין ${field.min} ל-${field.max}`;
        }
      }
    });
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (validate()) {
      alert(`טופס הוזן:\n${JSON.stringify(formData, null, 2)}`);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      {formFields.map(field => (
        <div key={field.id} style={{ marginBottom: '1rem' }}>
          <label>
            {field.label}
            {field.type === 'checkbox' ? (
              <input
                type="checkbox"
                checked={!!formData[field.id]}
                onChange={e => handleChange(field.id, e.target.checked, field.type)}
              />
            ) : (
              <input
                type={field.type}
                value={formData[field.id] || ''}
                onChange={e => handleChange(field.id, e.target.value, field.type)}
                placeholder={field.placeholder}
                style={{ width: '100%', padding: '0.5rem' }}
              />
            )}
          </label>
          {errors[field.id] && (
            <div style={{ color: 'red', fontSize: '0.85rem' }}>{errors[field.id]}</div>
          )}
        </div>
      ))}
