    type: 'checkbox'
  }
];

function DynamicForm() {
  const [formData, setFormData] = useState({});
  const [errors, setErrors] = useState({});

  const handleChange = (id, value, type) => {
    // המרת ערך ל-boolean אם זה checkbox
    const finalValue = type === 'checkbox' ? value : value;

    setFormData(prev => ({
      ...prev,
      [id]: finalValue
    }));

    // ניקוי שגיאה אם השדה נערך
    if (errors[id]) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors[id];
        return newErrors;
      });
    }
  };

  const validate = () => {
    const newErrors = {};
    formFields.forEach(field => {
      const value = formData[field.id];
      if (field.required && (value === undefined || value === '')) {
        newErrors[field.id] = 'שדה חובה';
      }
      if (field.type === 'number' && value !== undefined) {
        const num = Number(value);
        if (isNaN(num) || (field.min !== undefined && num < field.min) || (field.max !== undefined && num > field.max)) {
          newErrors[field.id] = `ערך חייב להיות בין ${field.min} ל-${field.max}`;
        }
      }
    });
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (validate()) {
      alert(`טופס הוזן:\n${JSON.stringify(formData, null, 2)}`);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      {formFields.map(field => (
        <div key={field.id} style={{ marginBottom: '1rem' }}>
