// model.js
const mongoose = require('mongoose');

const studentSchema = new mongoose.Schema({
  id: {
    type: String,
    required: true,
    unique: true, // מבטיח ייחודיות ברמת המאגר
    trim: true
  },
  name: {
    type: String,
    required: true
  },
  email: {
    type: String,
    required: true,
    unique: true
  }
}, { versionKey: false });

// בדיקה מוקדמת (למשל, אם לא רוצים להסתמך רק על unique ב-DB)
studentSchema.statics.existsById = async function(id) {
  return await this.findOne({ id }).exec() !== null;
};

const Student = mongoose.model('Student', studentSchema);
module.exports = Student;
```

```javascript
// controller.js
const Student = require('./model');

async function createStudent(req, res) {
  const { id, name, email } = req.body;

  // בדיקה ידנית (למשל, אם רוצים שליטה מדויקת יותר או בדיקה מוקדמת)
  try {
    const exists = await Student.existsById(id);
    if (exists) {
      return res.status(409).json({ error: 'ERROR: Student with this ID already exists' });
    }

    const newStudent = new Student({ id, name, email });
    await newStudent.save();

    res.status(201).json({ message: 'Student created successfully' });
  } catch (err) {
    // טיפול בשגיאות (למשל, ID לא תקין, תקלה ב-DB וכו')
    if (err.code === 11000) { // שגיאת ייחודיות של MongoDB
      return res.status(409).json({ error: 'ERROR: Duplicate ID' });
    }
    res.status(500).json({ error: 'ERROR: Internal server error' });
  }
}
```

4. **מלכודת נפוצה**  
- **שכפול ID רק ב-DB, לא ב-Application Layer** – אם לא בודקים את ה-ID לפני ה-`save`, ייתכן ש-`save()` יזרוק שגיאת ייחודיות (11000) רק אחרי ניסיון הכתיבה, מה שיכלול תהליך לא יעיל או שגיאות לא מטופלות.  
- **שכיחות של `unique: true` רק על שדה מסוים** – חשוב לוודא שה-ID מוגדר כ-`unique` גם ב-Schema וגם (אם יש צורך) ב-DB (למשל, אינדקס ייחודי).  
