const students = [
  { id: "123456789", average: 85 },
  { id: "987654321", average: 92 }
];

async function updateStudentAverage(id, newAverage) {
  try {
    // בדיקה אם הת"ז קיימת
    const studentIndex = students.findIndex(s => s.id === id);
    if (studentIndex === -1) {
      throw new Error("Student not found");
    }

    // עדכון הממוצע
    students[studentIndex].average = newAverage;

    // החזרת הודעה מוצלחת
    return { success: true, message: "Update successful" };
  } catch (error) {
    // החזרת ERROR – לפי דרישת המשימה
    return "ERROR";
  }
}

