```jsx
import React, { useState } from 'react';

const ValidationForm = () => {
  const [formData, setFormData] = useState({
    name: '',
    age: '',
    email: '',
    sequenceNumber: ''
  });

  const [errors, setErrors] = useState({});

  // הגדרת כללים לאימות
  const validationRules = {
    name: {
      required: true,
      minLength: 2,
      maxLength: 50
    },
    age: {
      required: true,
      min: 1,
      max: 120
    },
    email: {
      required: true,
      pattern: /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    },
    sequenceNumber: {
      required: false,
      min: 1,
      max: 1000
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    // ננקה את השגיאה של השדה הזה בלחיצה
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  const validateField = (name, value) => {
    const rules = validationRules[name];
    if (!rules) return '';

    // בדיקת חובה
    if (rules.required && (!value || value.trim() === '')) {
      return `${name} הוא שדה חובה`;
    }

    // בדיקת אורך מינימלי/מקסימלי (למחרוזת)
    if (rules.minLength && value.length < rules.minLength) {
      return `${name} חייב להיות לפחות ${rules.minLength} תווים`;
    }
    if (rules.maxLength && value.length > rules.maxLength) {
      return `${name}不得超过 ${rules.maxLength} תווים`; // שגיאה טיפוסית – תוקנה להלן
    }

    // בדיקת טווח (למספרים)
    if (rules.min !== undefined || rules.max !== undefined) {
      const num = parseFloat(value);
      if (isNaN(num)) {
        return `${name} חייב להיות מספר`;
      }
      if (rules.min !== undefined && num < rules.min) {
        return `${name} חייב להיות לפחות ${rules.min}`;
      }
      if (rules.max !== undefined && num > rules.max) {
        return `${name} חייב להיות לכל היותר ${rules.max}`;
      }
    }

    // בדיקת regex
    if (rules.pattern && value && !rules.pattern.test(value)) {
      return `${name} לא בתבנית תקינה`;
    }

    return '';
  };

  const validateForm = () => {
    const newErrors = {};
    for (const field in formData) {
      const error = validateField(field, formData[field]);
      if (error) newErrors[field] = error;
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (validateForm()) {
      alert('הטופס תקין! נשלח.');
      // כאן אפשר לשלוח לשרת
    } else {
      console.log('שגיאות:', errors);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label>שם:</label>
        <input
          name="name"
          value={formData.name}
          onChange={handleChange}
        />
        {errors.name && <span style={{ color: 'red' }}>{errors.name}</span>}
      </div>

      <div>
        <label>גיל:</label>
        <input
          name="age"
          type="number"
          value={formData.age}
          onChange={handleChange}
        />
        {errors.age && <span style={{ color: 'red' }}>{errors.age}</span>}
      </div>

      <div>
        <label>אימייל:</label>
        <input
          name="email"
          value={formData.email}
          onChange={handleChange}
        />
        {errors.email && <span style={{ color: 'red' }}>{errors.email}</span>}
      </div>

      <div>
        <label>מספר סדרה (למשל: 42):</label>
        <input
          name="sequenceNumber"
          type="number"
          value={formData.sequenceNumber}
          onChange={handleChange}
        />
        {errors.sequenceNumber && <span style={{ color: 'red' }}>{errors.sequenceNumber}</span>}
      </div>

      <button type="submit">שליחה</button>
    </form>
  );
};

export default ValidationForm;
```

