    console.log(await checkSequence([3, 9, 27, 81]));   // B – הנדסית
    console.log(await checkSequence([0, 1, 1, 2, 3]));  // C – פיבונאצי
    console.log(await checkSequence([1, 2, 4, 7]));     // D – אחרת
    console.log(await checkSequence([1, 'a', 3]));      // TypeError
  } catch (err) {
