const fs = require('fs').promises;
const path = require('path');

(async () => {
  const testFile = path.join(__dirname, 'test.txt');
  try {
    // 1. יצירת מופע – יוצר קובץ אם לא קיים
    const fp = new FilePackage(testFile);
    const exists = await fs.access(testFile).then(() => true).catch(() => false);
    console.log('קובץ נוצר:', exists); // true

    // 2. הוספת תוכן
    await fp.appendContent('שלום עולם');
    const content = await fs.readFile(testFile, 'utf8');
    console.log('תוכן after append:', content); // 'שלום עולם'

    // 3. חיפוש מילה
    const found = await fp.searchWord('עולם');
    console.log('נמצאה המילה "עולם":', found); // true

    // 4. שינוי שם
    const newFile = path.join(__dirname, 'renamed.txt');
    await fp.rename(newFile);
    const renamedExists = await fs.access(newFile).then(() => true).catch(() => false);
    console.log('הקובץ הוחלף בשם חדש:', renamedExists); // true

    // 5. העתקה
    const copiedFile = path.join(__dirname, 'copy.txt');
    await fp.copy(copiedFile);
    const copiedContent = await fs.readFile(copiedFile, 'utf8');
    console.log('תוכן הקובץ המועתק:', copiedContent); // 'שלום עולם'

    // ניקוי
    await fs.unlink(testFile).catch(() => {});
    await fs.unlink(newFile).catch(() => {});
    await fs.unlink(copiedFile).catch(() => {});

    console.log('כל הבדיקות עבדו בהצלחה!');
  } catch (err) {
    console.error('שגיאה בבדיקות:', err);
  }
})();
