const SignupForm = () => {
  const [id, setId] = useState('');
  const [fullName, setFullName] = useState('');
  const [idError, setIdError] = useState('');
  const [nameError, setNameError] = useState('');

  // אימות מספר עובד: בדיוק 5 ספרות
  const validateId = (value) => {
    const regex = /^\d{5}$/;
    if (!value) return 'the number must be with 5 digits.';
    return regex.test(value) ? '' : 'the number must be with 5 digits.';
  };

