3. **קוד**  
```jsx
import React, { useState } from 'react';

const VolunteerLocationInput = () => {
  const [location, setLocation] = useState('');
  const [error, setError] = useState('');

  const validateLocation = (value) => {
    if (!value.trim()) {
      return 'שדה חובה';
    }
    if (value.length < 2 || value.length > 30) {
      return 'שם העיר חייב להיות בין 2 ל-30 אותיות';
    }
    if (!/^[A-Za-z]+$/.test(value)) {
      return 'שם העיר חייב להכיל רק אותיות אנגליות (ללא מספרים, רווחים או סימנים)';
    }
    return '';
  };

  const handleChange = (e) => {
    const value = e.target.value;
    setLocation(value);
    // אפשר לאמת ב real-time, או רק ב-blur/submit – כאן נשמור את השגיאה עד ל-blur
    if (value) {
      setError(validateLocation(value));
    } else {
      setError('');
    }
  };

  const handleBlur = () => {
    setError(validateLocation(location));
  };

  return (
    <div>
      <label>
        מיקום ההתנדבות (שם עיר):
        <input
          type="text"
          value={location}
          onChange={handleChange}
          onBlur={handleBlur}
          placeholder="למשל: TelAviv"
          style={{ borderColor: error ? 'red' : 'black' }}
        />
      </label>
      {error && <p style={{ color: 'red', margin: '5px 0 0 0' }}>{error}</p>}
    </div>
  );
};

export default VolunteerLocationInput;
```

