import React, { useState } from 'react';

const VolunteerForm = () => {
  const [volunteerName, setVolunteerName] = useState('');
  const [error, setError] = useState('');

  const handleChange = (e) => {
    const value = e.target.value;
    setVolunteerName(value);

    // אימות רציף – מנקה את השגיאה אם הערך הופך תקין
    if (value.length > 2) {
      setError('');
    } else if (value.length > 0) {
      setError('שם חייב להיות באורך של לפחות 3 תווים');
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (volunteerName.length <= 2) {
      setError('שם חייב להיות באורך של לפחות 3 תווים');
      return;
    }
    // כאן אפשר לשלוח את הנתונים (למשל ל-API או ל-state גלובלי)
    console.log('Name submitted:', volunteerName);
    setError('');
    setVolunteerName('');
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label htmlFor="volunteerName">שם המתנדב:</label>
        <input
          id="volunteerName"
          type="text"
          value={volunteerName}
          onChange={handleChange}
          placeholder="הקלד שם (לפחות 3 תווים)"
        />
        {error && <p style={{ color: 'red' }}>{error}</p>}
      </div>
      <button type="submit" disabled={!!error}>
        שלח
      </button>
    </form>
  );
};

export default VolunteerForm;
```

4. **מלכודת נפוצה**  
- לשכוח לעדכן את שגיאת האימות גם ב-`onChange` (לא רק ב-`onSubmit`) – זה גורם למשתמש להישאר עם שגיאה גם אחרי תיקון.  
- לא לנקות את השגיאה אחרי שהמשתמש מתקן את הערך – זה גורם לשגיאה להישאר גם אחרי שהמשתמש הקליד שם תקין.  
- לא לשלוח את ה-event ב-`onSubmit` (למשל `e.preventDefault()` חסר) – זה גורם לרענון דף אוטומטי, ומאבד את ה-state.

5. **בדיקת תקינות**  
- ✅ שדה טקסט עם `value` ו-`onChange`.  
- ✅ אימות: רק ערכים באורך > 2 מתקבלים.  
- ✅ הצגת שגיאה (text ב-`<p>` אדום).  
- ✅ דטרמיניסטי – לא קיימים ערכים חיצוניים, כל מה שנדרש קיים ב-state.  
- ✅ ניקיון שגיאות עם תיקון הערך.  
