import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const VolunteerSearchForm = () => {
  const navigate = useNavigate();

  // ערכי השדות
  const [formData, setFormData] = useState({
    city: '',
  });

  // שגיאות אימות
  const [errors, setErrors] = useState({});

  // הגדרת כללי אימות
  const validationRules = {
    city: {
      required: true,
      minLength: 2,
      maxLength: 50,
      pattern: /^[א-ת\s]+$/ // רק תווים עברי'ים ורווחים
    }
  };

  // פונקציה לאימות שדה בודד
  const validateField = (name, value) => {
    const rules = validationRules[name];
    if (!rules) return '';

    if (rules.required && !value.trim()) {
      return 'שדה חובה';
    }

    if (rules.minLength && value.length < rules.minLength) {
      return `הערך חייב להיות לפחות ${rules.minLength} תווים`;
    }

    if (rules.maxLength && value.length > rules.maxLength) {
      return `הערך חייב להיות לכל היותר ${rules.maxLength} תווים`;
    }

    if (rules.pattern && !rules.pattern.test(value)) {
      return 'הערך חייב להיות בעברית בלבד';
    }

    return '';
  };

  // עדכון ערך + אימות רלוונטי
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    setErrors(prev => ({
      ...prev,
      [name]: validateField(name, value)
    }));
  };

  // בדיקת כל השדות
  const validateForm = () => {
    const newErrors = {};
    Object.keys(validationRules).forEach(key => {
      const error = validateField(key, formData[key]);
      if (error) newErrors[key] = error;
    });
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // שליחה / חיפוש
  const handleSearch = (e) => {
    e.preventDefault();
    if (!validateForm()) {
      alert('אנאתקן את השגיאות בטופס');
      return;
    }
    navigate('/all', { state: { city: formData.city } });
  };

  return (
    <form onSubmit={handleSearch}>
      <div>
        <label>עיר:</label>
        <input
          type="text"
          name="city"
          value={formData.city}
          onChange={handleChange}
          placeholder="הקלד עיר"
        />
        {errors.city && <span style={{ color: 'red' }}>{errors.city}</span>}
      </div>

      <button type="submit">חפש</button>
    </form>
  );
};

export default VolunteerSearchForm;

