  const [description, setDescription] = useState('');
  const [errors, setErrors] = useState({});

  const validationRules = {
    required: true,
    minLength: 5,
    maxLength: 200,
    regex: /^[a-zA-Z0-9 .,!?'-]*$/
  };

  const validateField = (value) => {
    const newErrors = {};

    if (validationRules.required && !value.trim()) {
