    }

    if (value.length > validationRules.maxLength) {
      newErrors.maxLength = `התיאור不得超过 ${validationRules.maxLength} תווים`;
    }

    if (validationRules.regex && !validationRules.regex.test(value)) {
      newErrors.regex = 'התיאור מכיל תווים לא תקפים';
    }

    return newErrors;
  };

