```jsx
// App.js
import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useNavigate } from 'react-router-dom';
import Signin from './Signin';
import Home from './Home';
import Client from './Client';

// הרכיב שמכיל את ה-Router (הנחיית SVCollege: כל קוד חייב להיות דטרמיניסטי)
function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  return (
    <Router>
      <Routes>
        <Route
          path="/signin"
          element={<Signin onLogin={() => setIsAuthenticated(true)} />}
        />
        <Route
          path="/home"
          element={isAuthenticated ? <Home onLogout={() => setIsAuthenticated(false)} /> : <Navigate to="/signin" replace />}
        />
        <Route
          path="/client"
          element={isAuthenticated ? <Client onBack={() => {}} /> : <Navigate to="/signin" replace />}
        />
        <Route path="/" element={<Navigate to={isAuthenticated ? "/home" : "/signin"} replace />} />
      </Routes>
    </Router>
  );
}

export default App;
```

