import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const AddFlightForm = ({ flights, setFlights }) => {
  const navigate = useNavigate();

  const [flightNumber, setFlightNumber] = useState('');
  const [airline, setAirline] = useState('');
  const [passengers, setPassengers] = useState('');
  const [error, setError] = useState('');

  const validateFlight = () => {
    // Reset error
    setError('');

    // Validate flight number: numeric, up to 5 chars, unique
    if (!/^\d{1,5}$/.test(flightNumber)) {
      return 'מספר טיסה חייב להיות מספרי וברור עד 5 תווים.';
    }
    if (flights.some(f => f.flightNumber === flightNumber)) {
      return 'מספר טיסה כבר קיים.';
    }

    // Validate airline: at least one letter
    if (!/[a-zA-Z]/.test(airline) || airline.trim().length === 0) {
      return 'חברת תעופה חייבת להכיל לפחות אות אחת.';
    }

    // Validate passengers: number between 1 and 450
    const numPassengers = Number(passengers);
    if (isNaN(numPassengers) || !Number.isInteger(numPassengers)) {
      return 'מספר נוסעים חייב להיות מספר שלם.';
    }
    if (numPassengers < 1 || numPassengers > 450) {
      return 'מספר נוסעים חייב להיות בין 1 ל-450.';
    }

    return null; // valid
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const errorMsg = validateFlight();
    if (errorMsg) {
      alert(errorMsg);
      return;
    }

    const newFlight = {
      flightNumber,
      airline: airline.trim(),
      passengers: Number(passengers),
    };

    setFlights(prev => [...prev, newFlight]);
    navigate('/controlpanel');
  };

  return (
    <form onSubmit={handleSubmit} style={{ padding: '20px' }}>
      <h2>הוספת טיסה חדשה</h2>

      <div style={{ marginBottom: '10px' }}>
        <label>
          מספר טיסה:
          <input
            type="text"
            value={flightNumber}
            onChange={(e) => setFlightNumber(e.target.value.replace(/\D/g, ''))}
            maxLength={5}
            style={{ width: '100%', padding: '8px', marginTop: '5px' }}
          />
        </label>
      </div>

      <div style={{ marginBottom: '10px' }}>
        <label>
          חברת תעופה:
          <input
            type="text"
            value={airline}
            onChange={(e) => setAirline(e.target.value)}
            style={{ width: '100%', padding: '8px', marginTop: '5px' }}
          />
        </label>
      </div>

      <div style={{ marginBottom: '10px' }}>
        <label>
          מספר נוסעים:
          <input
            type="number"
            value={passengers}
            onChange={(e) => setPassengers(e.target.value)}
            min={1}
            max={450}
            style={{ width: '100%', padding: '8px', marginTop: '5px' }}
          />
        </label>
      </div>

      <button type="submit" style={{ padding: '10px 20px' }}>
        הוסף טיסה
      </button>
    </form>
  );
};

export default AddFlightForm;
```

