```jsx
import React, { useState } from 'react';

const AddFlight = ({ flights, setFlights, navigate }) => {
  const [flightNumber, setFlightNumber] = useState('');
  const [airline, setAirline] = useState('');
  const [passengers, setPassengers] = useState('');
  const [errors, setErrors] = useState({});

  const validateField = (name, value) => {
    let error = '';
    switch (name) {
      case 'flightNumber':
        if (!/^\d{1,5}$/.test(value)) {
          error = 'מספר טיסה חייב להיות ספרתי וברור 1-5 תווים.';
        } else if (flights.some(f => f.flightNumber === value)) {
          error = 'מספר הטיסה כבר קיים.';
        }
        break;
      case 'airline':
        if (!value.trim() || !/[a-zA-Z]/.test(value)) {
          error = 'חברת תעופה חייבת להכיל לפחות אות אחת.';
        }
        break;
      case 'passengers':
        const num = parseInt(value, 10);
        if (isNaN(num) || num < 1 || num > 450) {
          error = 'מספר הנוסעים חייב להיות בין 1 ל-450.';
        }
        break;
      default:
        break;
    }
    return error;
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    if (name === 'flightNumber') setFlightNumber(value.replace(/\D/g, '')); // רק ספרות
    else if (name === 'passengers') setPassengers(value.replace(/\D/g, '')); // רק ספרות
    else setAirline(value);

    // בדיקה רגשית (ללא alert עדיין)
    const error = validateField(name, value);
    setErrors(prev => ({ ...prev, [name]: error }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // בדיקת כל השדות
    const newErrors = {
      flightNumber: validateField('flightNumber', flightNumber),
      airline: validateField('airline', airline),
      passengers: validateField('passengers', passengers),
    };

    setErrors(newErrors);

    // אם יש שגיאות – מציגים alert עם השגיאה הראשונה
    const firstError = Object.values(newErrors).find(err => err);
    if (firstError) {
      alert(firstError);
      return;
    }

    // הוספת טיסה
    const newFlight = {
      flightNumber,
      airline: airline.trim(),
      passengers: parseInt(passengers, 10),
    };
    setFlights(prev => [...prev, newFlight]);
    navigate('/controlpanel'); // חזרה לרשימה
  };

  return (
    <div>
      <h2>הוספת טיסה</h2>
      <form onSubmit={handleSubmit}>
        <div>
          <label>מספר טיסה (1-5 ספרות, ייחודי):</label>
          <input
            name="flightNumber"
            value={flightNumber}
            onChange={handleInputChange}
            placeholder="למשל: 1234"
          />
          {errors.flightNumber && <span style={{ color: 'red' }}>{errors.flightNumber}</span>}
        </div>

        <div>
          <label>חברת תעופה (לפחות אות אחת):</label>
          <input
            name="airline"
            value={airline}
            onChange={handleInputChange}
            placeholder="למשל: El Al"
          />
          {errors.airline && <span style={{ color: 'red' }}>{errors.airline}</span>}
        </div>

        <div>
          <label>מספר נוסעים (1-450):</label>
          <input
            name="passengers"
            value={passengers}
            onChange={handleInputChange}
            placeholder="למשל: 200"
          />
          {errors.passengers && <span style={{ color: 'red' }}>{errors.passengers}</span>}
        </div>

        <button type="submit">הוסף טיסה</button>
      </form>
    </div>
  );
};

export default AddFlight;
```

