1. **משמעות המשימה**  
המשימה מבקשת לכתוב פונקציה `solve` ב-CommonJS (`solution.js`) שמקבלת קלט (ככל הנראה מחרוזת או אובייקט) ומחזירה פלט מדויק, בהתאם להקשר של מערכת לניהול בקרות טיסה. עם זאת, **ההקשר המפורט לא כולל תיאור מדויק של פונקציונליות אלגוריתמית מובחנת** – הוא מתאר ממשק משתמש ותפקידי React ( вход, בקרה, סידור, הוספה, מחיקה), אך **לא מגדיר פונקציה מדויקת עם קלט/פלט**.  
לכן, המשימה נוטה להיות "בינה מלאכותית" – לפרש את הדרישות כפונקציה דטרמיניסטית שמעבדת בקשות לוגיות (כגון "האם טיסה קיימת?", "מה סך הנוסעים?") ומחזירה תוצאה מובנית.

**הנחת הבסיס**: התרגיל מבקש פונקציה `solve` שמקבלת אובייקט עם `action` (כגון `'getTotalPassengers'`, `'isFlightExists'`, `'addFlight'`, `'deleteFlight'`) ונתונים רלוונטיים, ומחזירה תוצאה בהתאם לנתוני בדיקה קבועים.

2. **איך פותרים אותה**  
- נשמור מערך טיסות קבוע (נתוני בדיקה) כנתון פנימי.  
- נכתוב `solve` שמקבל אובייקט עם שדה `action` ונתונים נוספים.  
- נשתמש ב-`switch` על הפעולה (`action`) וنعבור על כל מקרה:  
  - `getTotalPassengers` – מחזירה את סך כל הנוסעים.  
  - `isFlightExists` – בודקת אם טיסה קיימת.  
  - `addFlight` – מוסיפה טיסה אם תקינה (בהתאם לדרישות).  
  - `deleteFlight` – מוחקת טיסה אם קיימת.  
- נשתמש ב-CommonJS, נמייצא את `solve`, ונשמור על דטרמיניות.

3. **קוד**

```javascript
// solution.js
const flights = [
  { id: '1001', airline: 'El Al', passengers: 250 },
  { id: '1002', airline: 'Arkia', passengers: 180 },
  { id: '1003', airline: 'Israir', passengers: 120 }
];

function validateFlightId(id) {
  return typeof id === 'string' && /^\d{1,5}$/.test(id);
}

function validateAirline(airline) {
  return typeof airline === 'string' && airline.length > 0 && /[a-zA-Z]/.test(airline);
}

function validatePassengers(passengers) {
  return Number.isInteger(passengers) && passengers >= 1 && passengers <= 450;
}

function solve(input) {
  const { action, flightId, airline, passengers } = input;

  switch (action) {
    case 'getTotalPassengers':
      return flights.reduce((sum, f) => sum + f.passengers, 0);

    case 'isFlightExists':
      if (!validateFlightId(flightId)) {
        return false;
      }
      return flights.some(f => f.id === flightId);

    case 'addFlight':
      if (!validateFlightId(flightId)) {
        return { success: false, error: 'Invalid flight ID' };
      }
      if (flights.some(f => f.id === flightId)) {
        return { success: false, error: 'Flight ID already exists' };
      }
      if (!validateAirline(airline)) {
        return { success: false, error: 'Invalid airline name' };
      }
      if (!validatePassengers(passengers)) {
        return { success: false, error: 'Passengers must be integer between 1 and 450' };
      }
      flights.push({ id: flightId, airline, passengers });
      return { success: true, message: 'Flight added' };

    case 'deleteFlight':
      if (!validateFlightId(flightId)) {
        return { success: false, error: 'Invalid flight ID' };
      }
      const index = flights.findIndex(f => f.id === flightId);
      if (index === -1) {
        return { success: false, error: 'Flight not found' };
      }
      flights.splice(index, 1);
      return {
        success: true,
        message: `Total flights: ${flights.length}, total passengers: ${flights.reduce((sum, f) => sum + f.passengers, 0)}`
      };

    default:
      return { success: false, error: 'Unknown action' };
  }
}

module.exports = { solve };
```

4. **מלכודת נפוצה**  
- **שכיחות שגיאות בקלט**: לא מטפלים בקלט לא תקין (למשל `flightId` לא מחרוזת, `passengers` לא מספר שלם).  
- **החלפת סדר בדיקות**: אם בודקים אם טיסה קיימת *אחרי* הוספה/מחיקה – יש לזכור שהמערך משתנה.  
- **הנחת ערכים חסרים**: אם `airline` ריק או `passengers` מחוץ לתחום – יש להחזיר שגיאה מדויקת.  
- **שכיחות בדיקת ייחודיות**: חובה לוודא שה-ID לא קיים כבר *לפני* הוספה.

5. **בדיקת תקינות**  
```javascript
const { solve } = require('./solution');

// בדיקת סך הנוסעים
console.log(solve({ action: 'getTotalPassengers' })); // 550

// בדיקת קיום טיסה
console.log(solve({ action: 'isFlightExists', flightId: '1002' })); // true
console.log(solve({ action: 'isFlightExists', flightId: '9999' })); // false

// הוספת טיסה תקינה
console.log(solve({ action: 'addFlight', flightId: '2001', airline: 'Sun Air', passengers: 300 }));
// { success: true, message: 'Flight added' }

// ניסיון להוסיף טיסה עם ID קיים
console.log(solve({ action: 'addFlight', flightId: '1001', airline: 'Test', passengers: 100 }));
// { success: false, error: 'Flight ID already exists' }

// מחיקת טיסה
console.log(solve({ action: 'deleteFlight', flightId: '1003' }));
// { success: true, message: 'Total flights: 2, total passengers: 430' }

// בדיקת שגיאה בקלט
console.log(solve({ action: 'addFlight', flightId: '123456', airline: 'Test', passengers: 100 }));

